// ─── Helpers ────────────────────────────────────────────────────────────────────

func findInfo(id string, infos []*model.NodeInfo) *model.NodeInfo {
	for _, ni := range infos {
		if ni != nil && ni.ID == id {
			return ni
		}
	}
	return nil
}

func findMetric(id string, metrics []*model.NodeMetrics) *model.NodeMetrics {
	for _, m := range metrics {
		if m != nil && m.HostID == id {
			return m
		}
	}
	return nil
}

func niCountry(nodeInfo []*model.NodeInfo) string {
	if len(nodeInfo) > 0 && nodeInfo[0] != nil {
		return nodeInfo[0].Country
	}
	return ""
}

func niBandwidth(nodeInfo []*model.NodeInfo) string {
	if len(nodeInfo) > 0 && nodeInfo[0] != nil {
		return nodeInfo[0].Bandwidth
	}
	return ""
}

func containsStr(slice []string, item string) bool {
	for _, s := range slice {
		if s == item {
			return true
		}
	}
	return false
}

func niSource(nodeInfo []*model.NodeInfo) string {
	if len(nodeInfo) > 0 && nodeInfo[0] != nil {
		return nodeInfo[0].Source
	}
	return ""
}

